import json
import sys
import re

def classify_columns(data):
    columns = data["columns"]

    direct_patterns = [
        r"(?i)(full_?name|first_?name|last_?name|sur_?name|^name$)",
        r"(?i)(email|e_mail)",
        r"(?i)(phone|mobile|tel)",
        r"(?i)(passport|inn|snils|ssn)"
    ]
    quasi_patterns = [
        r"(?i)(birth_?date|dob|date_of_birth)",
        r"(?i)(zip_?code|postal)",
        r"(?i)(gender|sex)"
    ]
    sensitive_patterns = [
        r"(?i)(salary|income|compensation)",
        r"(?i)(diagnosis|medical|health)",
        r"(?i)(religion|political)"
    ]

    classifications = []
    counts = {"direct_identifiers": 0, "quasi_identifiers": 0, "sensitive": 0, "non_pii": 3}
    counts["non_pii"] = 0

    for col in columns:
        name = col["name"]
        category = "none"
        confidence = "high"

        for p in direct_patterns:
            if re.search(p, name):
                category = "direct_identifier"
                break

        if category == "none":
            for p in quasi_patterns:
                if re.search(p, name):
                    category = "quasi_identifier"
                    break

        if category == "none":
            for p in sensitive_patterns:
                if re.search(p, name):
                    category = "sensitive"
                    break

        if category == "none":
            samples = col.get("sample_values", [])
            has_email = any(re.match(r"^[^@]+@[^@]+\.[a-zA-Z]{2,}$", str(v)) for v in samples)
            has_phone = any(re.match(r"^\+7\d{10}$", str(v)) for v in samples)
            if has_email:
                category = "direct_identifier"
            elif has_phone:
                category = "direct_identifier"
            else:
                confidence = "medium" if name.startswith("department") or name in ["department"] else "high"

        if category == "direct_identifier":
            counts["direct_identifiers"] += 1
        elif category == "quasi_identifier":
            counts["quasi_identifiers"] += 1
        elif category == "sensitive":
            counts["sensitive"] += 1
        else:
            counts["non_pii"] += 1

        classifications.append({"column": name, "pii_category": category, "confidence": confidence})

    total_pii = counts["direct_identifiers"] + counts["quasi_identifiers"] + counts["sensitive"]

    result = {
        "classifications": classifications,
        "summary": {
            "direct_identifiers": counts["direct_identifiers"],
            "quasi_identifiers": counts["quasi_identifiers"],
            "sensitive": counts["sensitive"],
            "non_pii": counts["non_pii"],
            "total_pii_columns": total_pii
        }
    }

    print(json.dumps(result, indent=2))

data = json.loads(sys.stdin.read())
classify_columns(data)
